int AccountDataStub::OnRemoteRequest(uint32_t code, MessageParcel &data, MessageParcel &reply, MessageOption &option)
{
    if (data.ReadInterfaceToken() != GetDescriptor()) {
        return ERR_INVALID_DATA;
    }
    switch (code) {
        case TRANS_DELETE_ACCOUNT_CACHE:
            return HandleDeleteAccountCache(data, reply);
        case TRANS_QUERY_OWN_ACCOUNT:
            return HandleQueryOwnAccount(data, reply);
        default:
            return IPCObjectStub::OnRemoteRequest(code, data, reply, option);
    }
}

int AccountDataStub::HandleDeleteAccountCache(MessageParcel &data, MessageParcel &reply)
{
    uint32_t tokenId = data.ReadUint32();
    int32_t targetUserId = data.ReadInt32();
    std::string bundleName = data.ReadString();
    if (!AccessTokenKit::VerifyAccessToken(tokenId, "ohos.permission.CLEAN_ACCOUNT_CACHE")) {
        HILOG_WARN(LOG_CORE, "clean cache permission denied for %{public}s", bundleName.c_str());
        return ERR_PERMISSION_DENIED;
    }
    accountStore_.DeleteCache(targetUserId, bundleName);
    reply.WriteInt32(ERR_OK);
    return ERR_OK;
}

int AccountDataStub::HandleQueryOwnAccount(MessageParcel &data, MessageParcel &reply)
{
    uint32_t callerToken = IPCSkeleton::GetCallingTokenID();
    int32_t userId = GetUserIdByToken(callerToken);
    std::string bundleName = GetBundleNameByToken(callerToken);
    reply.WriteString(accountStore_.Query(userId, bundleName));
    return ERR_OK;
}
