int MediaImportStub::OnRemoteRequest(uint32_t code, MessageParcel &data, MessageParcel &reply, MessageOption &option)
{
    if (data.ReadInterfaceToken() != GetDescriptor()) {
        return ERR_INVALID_DATA;
    }
    if (code == TRANS_IMPORT_PHOTOS) {
        return ImportPhotos(data, reply);
    }
    if (code == TRANS_IMPORT_PHOTOS_SAFE) {
        return ImportPhotosSafe(data, reply);
    }
    return IPCObjectStub::OnRemoteRequest(code, data, reply, option);
}

int MediaImportStub::ImportPhotos(MessageParcel &data, MessageParcel &reply)
{
    int32_t count = data.ReadInt32();
    int fd = data.ReadFileDescriptor();
    sptr<IRemoteObject> callback = data.ReadRemoteObject();
    importCallbacks_.push_back(callback);

    std::vector<PhotoMeta> metas(count);
    for (int32_t i = 0; i < count; ++i) {
        metas[i].name = data.ReadString();
        metas[i].size = data.ReadInt64();
    }
    importer_.ImportFromFd(fd, metas, callback);
    reply.WriteInt32(ERR_OK);
    return ERR_OK;
}

int MediaImportStub::ImportPhotosSafe(MessageParcel &data, MessageParcel &reply)
{
    int32_t count = 0;
    if (!data.ReadInt32(count) || count < 0 || count > MAX_IMPORT_COUNT) {
        return ERR_INVALID_DATA;
    }
    int fd = data.ReadFileDescriptor();
    if (fd < 0) {
        return ERR_INVALID_DATA;
    }
    UniqueFd importFd(fd);
    sptr<IRemoteObject> callback = data.ReadRemoteObject();
    if (callback == nullptr) {
        return ERR_INVALID_DATA;
    }
    std::vector<PhotoMeta> metas;
    metas.reserve(count);
    for (int32_t i = 0; i < count; ++i) {
        std::string name;
        int64_t size = 0;
        if (!data.ReadString(name) || !data.ReadInt64(size) || size < 0 || size > MAX_PHOTO_SIZE) {
            return ERR_INVALID_DATA;
        }
        metas.push_back({name, size});
    }
    importer_.ImportFromFd(importFd.Get(), metas, callback);
    reply.WriteInt32(ERR_OK);
    return ERR_OK;
}
