```cpp
int NotificationCallbackManager::RegisterCallback(MessageParcel &data)
{
    int32_t userId = data.ReadInt32();
    sptr<IRemoteObject> remote = data.ReadRemoteObject();
    if (remote == nullptr) {
        return ERR_INVALID_DATA;
    }
    std::lock_guard<std::mutex> lock(callbackMutex_);
    callbacks_[userId].push_back(remote);
    remote->AddDeathRecipient(deathRecipient_);
    return ERR_OK;
}

void NotificationCallbackManager::UnregisterCallback(int32_t userId, const sptr<IRemoteObject> &remote)
{
    auto &list = callbacks_[userId];
    list.erase(std::remove(list.begin(), list.end(), remote), list.end());
}

void NotificationCallbackManager::OnRemoteDied(const wptr<IRemoteObject> &remote)
{
    for (auto &[userId, list] : callbacks_) {
        list.erase(std::remove(list.begin(), list.end(), remote.promote()), list.end());
    }
}

void NotificationCallbackManager::NotifyUser(int32_t userId, const Notice &notice)
{
    std::lock_guard<std::mutex> lock(callbackMutex_);
    for (auto &remote : callbacks_[userId]) {
        sptr<INoticeCallback> callback = iface_cast<INoticeCallback>(remote);
        if (callback != nullptr) {
            callback->OnNotice(notice);
        }
    }
}
