int LocationPolicyStub::OnRemoteRequest(uint32_t code, MessageParcel &data, MessageParcel &reply, MessageOption &option)
{
    if (data.ReadInterfaceToken() != GetDescriptor()) {
        return ERR_INVALID_DATA;
    }
    switch (code) {
        case TRANS_UPDATE_POLICY:
            return UpdatePolicy(data, reply);
        default:
            return IPCObjectStub::OnRemoteRequest(code, data, reply, option);
    }
}

bool LocationPolicyStub::EnforceUpdatePolicyPermission(int32_t targetUserId) const
{
    uint32_t tokenId = IPCSkeleton::GetCallingTokenID();
    if (AccessTokenKit::VerifyAccessToken(tokenId, "ohos.permission.MANAGE_LOCATION_POLICY") != PERMISSION_GRANTED) {
        return false;
    }
    if (targetUserId != GetUserIdByToken(tokenId) &&
        AccessTokenKit::VerifyAccessToken(tokenId, "ohos.permission.INTERACT_ACROSS_USERS") != PERMISSION_GRANTED) {
        return false;
    }
    return true;
}

int LocationPolicyStub::UpdatePolicy(MessageParcel &data, MessageParcel &reply)
{
    int32_t targetUserId = 0;
    bool enabled = false;
    std::string provider;
    if (!data.ReadInt32(targetUserId) || !data.ReadBool(enabled) || !data.ReadString(provider)) {
        return ERR_INVALID_DATA;
    }
    if (provider != "gps" && provider != "network") {
        return ERR_INVALID_DATA;
    }
    if (!EnforceUpdatePolicyPermission(targetUserId)) {
        return ERR_PERMISSION_DENIED;
    }
    policyStore_.SetLocationEnabled(targetUserId, provider, enabled);
    HILOG_INFO(LOG_CORE, "location policy updated result=%{public}d", ERR_OK);
    reply.WriteInt32(ERR_OK);
    return ERR_OK;
}
